"use strict";(self.webpackChunkscripting_doc=self.webpackChunkscripting_doc||[]).push([["50022"],{66270:function(e,n,t){t.r(n),t.d(n,{default:()=>c});var i=t(85893),a=t(50065);function o(e){let n=Object.assign({h1:"h1",a:"a",pre:"pre",code:"code"},(0,a.ah)(),e.components);return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)(n.h1,{id:"示例",children:["示例",(0,i.jsx)(n.a,{className:"header-anchor","aria-hidden":"true",href:"#示例",children:"#"})]}),"\n",(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{className:"language-tsx",children:"import { Button, List, Navigation, NavigationStack, Path, Script, Section, Text, } from \"scripting\"\n\nfunction Example() {\n  const dismiss = Navigation.useDismiss()\n\n  return <NavigationStack>\n    <List\n      navigationTitle={\"Speech Example\"}\n      navigationBarTitleDisplayMode={\"inline\"}\n      toolbar={{\n        cancellationAction: <Button\n          title={\"Done\"}\n          action={dismiss}\n        />\n      }}\n    >\n      <Section\n        footer={\n          <Text>Activate the SharedAudioSeesion, and speak a text.</Text>\n        }\n      >\n        <Button\n          title={\"Speak a text\"}\n          action={async () => {\n            console.present()\n            if (await Speech.isSpeaking) {\n              await Speech.stop('immediate')\n              console.log(\"Stopped.\")\n              return\n            }\n\n            await SharedAudioSession.setActive(true)\n            await SharedAudioSession.setCategory('playback', ['mixWithOthers'])\n\n            const listener = () => {\n              console.log(\"Speak completed!\")\n              Speech.removeListener('finish', listener)\n            }\n\n            Speech.addListener('finish', listener)\n\n            await Speech.speak('Hi there, welcome to Scripting! I wish this app is helpful to you.', {\n              voiceLanguage: 'en-US',\n            })\n\n            console.log(\"Started, tap the run button to stop.\")\n          }}\n        />\n      </Section>\n      <Section\n        footer={\n          <Text>Synthesize text to the file stored in local documents directory.</Text>\n        }\n      >\n        <Button\n          title={\"synthesize to File\"}\n          action={async () => {\n            console.present()\n            const filePath = Path.join(FileManager.documentsDirectory, 'greeting.caf')\n            const listener = () => {\n              if (FileManager.existsSync(filePath)) {\n                console.log(\"Audio file is saved to \" + filePath + \". Start to play it.\")\n\n                let player = new AVPlayer()\n                player.setSource(filePath)\n                player.onReadyToPlay = () => {\n                  player.play()\n                }\n                player.onEnded = () => {\n                  player.dispose()\n                }\n              } else {\n                console.log(\"Failed to save audio file.\")\n              }\n              Speech.removeListener('finish', listener)\n            }\n\n            Speech.addListener('finish', listener)\n\n            await Speech.synthesizeToFile(\n              'Hi there, welcome to Scripting! I wish this app is helpful to you.',\n              filePath, {\n              voiceLanguage: 'en-US',\n            })\n          }}\n        />\n      </Section>\n    </List>\n  </NavigationStack>\n}\n\nasync function run() {\n  await Navigation.present({\n    element: <Example />\n  })\n\n  Script.exit()\n}\n\nrun()\n"})})]})}function s(){let e=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},{wrapper:n}=Object.assign({},(0,a.ah)(),e.components);return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(o,{...e})}):o(e)}let c=s;s.__RSPRESS_PAGE_META={},s.__RSPRESS_PAGE_META["zh%2Fguide%2Fdoc_v2%2FDevice%20Capabilities%2FSpeech%2Findex_example.mdx"]={toc:[],title:"示例",headingTitle:"示例",frontmatter:{}}}}]);